// Get the data from the previous Airtable node
const airtableData = $input.all();

// Count valid records (filter out empty responses)
let recordCount = 0;

if (airtableData && Array.isArray(airtableData)) {
  recordCount = airtableData.filter(item => 
    item && 
    item.json && 
    Object.keys(item.json).length > 0 &&
    (item.json.id || item.json.fields)
  ).length;
}

return {recordCount}

// Get the input data from the previous node
const inputData = $input.all();

// Initialize aggregation object
const aggregated = {
  emails: [],
  phones: [],
  phonesUncertain: [],
  linkedIns: [],
  twitters: [],
  instagrams: [],
  facebooks: [],
  youtubes: [],
  tiktoks: [],
  pinterests: [],
  discords: [],
  referrerUrl: null,
  url: null,
  domain: null,
  originalStartUrl: null
};

// Process each item from the input
inputData.forEach(item => {
  const { 
    depth, 
    referrerUrl, 
    url, 
    domain, 
    emails = [], 
    phones = [], 
    phonesUncertain = [], 
    linkedIns = [], 
    twitters = [], 
    instagrams = [], 
    facebooks = [], 
    youtubes = [], 
    tiktoks = [], 
    pinterests = [], 
    discords = [], 
    originalStartUrl 
  } = item.json;

  // Aggregate array fields (avoid duplicates)
  const arrayFields = [
    'emails', 'phones', 'phonesUncertain', 'linkedIns', 
    'twitters', 'instagrams', 'facebooks', 'youtubes', 
    'tiktoks', 'pinterests', 'discords'
  ];

  arrayFields.forEach(field => {
    const fieldData = eval(field);
    if (Array.isArray(fieldData) && fieldData.length > 0) {
      fieldData.forEach(value => {
        if (value && !aggregated[field].includes(value)) {
          aggregated[field].push(value);
        }
      });
    }
  });

  // Set single value fields (use first non-null value)
  const singleFields = ['referrerUrl', 'url', 'domain', 'originalStartUrl'];
  singleFields.forEach(field => {
    const fieldValue = eval(field);
    if (!aggregated[field] && fieldValue) {
      aggregated[field] = fieldValue;
    }
  });
});

// Create output format that n8n expects
const output = [{
  json: {
    ...aggregated,
    // Additional metadata
    totalItemsProcessed: inputData.length,
    aggregationTimestamp: new Date().toISOString()
  }
}];

return output;

